UPDATE /* @SQLID=SUB0204_02-04_2#Sql011 */ ETINTRA.BB_ACCEPT
    SET
    BB_REMARK = #{req.bbRemark}
    ,BB_UPDATE_DATE = CORDYS.IFA_DATE_UTIL.IFA_GET_DATE
    ,BB_UPDATE_USER_ID = #{req.userId}
    ,BB_UPDATE_USER_NAME = #{req.userNm}
    ,BB_UPDATE_SECTION_ID = #{req.sectionId}
    ,BB_UPDATE_SECTION_NAME = #{req.branchName}
WHERE BB_PRODUCT_CODE = #{req.brandCode}
AND TRIM(BB_BRANCH_CODE) = #{req.butenCode}
AND TO_NUMBER(BB_ACCOUNT_NUMBER) = TO_NUMBER(LPAD(#{req.accountNumber}, 7, 0))
AND BB_PRESENTATION_FROM = TO_NUMBER(#{req.bookBuildingPresentationFrom})
